parser grammar SYsUParser;

options {
  tokenVocab=SYsULexer;
}

@parser::members {
    #include "ASTBuilder.h"
    #include <nlohmann/json.hpp>
    using json = nlohmann::json;

    ASTBuilder astBuilder;

    void printAST(const asg::Node* node) {
        json j = astBuilder.buildJSON(node);
        std::cout << j.dump(2) << std::endl;
    }
}

compilationUnit
    :   translationUnit? EOF
    ;

translationUnit
    :   externalDeclaration+
    ;

externalDeclaration
    :   functionDefinition
    |   declaration
    ;

functionDefinition
    : declarationSpecifiers declarator compoundStatement
    {
        auto func = astBuilder.makeFunction($declarator.ctx, $compoundStatement.ctx);
        printAST(func);
    }
    ;

declaration
    :   declarationSpecifiers initDeclaratorList? Semi
    {
        auto decls = astBuilder.makeDeclaration($declarationSpecifiers.ctx, $initDeclaratorList.ctx);
        for (auto decl : decls) {
            printAST(decl);
        }
    }
    ;

declarationSpecifiers
    :   typeSpecifier+
    ;

typeSpecifier
    :   Int
    |   Void
    ;

declarator
    :   Identifier
    |   declarator '[' ']'
    |   declarator '[' assignmentExpression ']'
    |   declarator '(' ')'
    |   declarator '(' parameterList ')'
    ;

initDeclaratorList
    :   initDeclarator (',' initDeclarator)*
    ;

initDeclarator
    :   declarator
    |   declarator '=' initializer
    ;

initializer
    :   assignmentExpression
    |   '{' initializerList '}'
    |   '{' '}'
    ;

initializerList
    :   initializer (',' initializer)*
    ;

compoundStatement
    :   '{' blockItemList? '}'
    ;

blockItemList
    :   blockItem+
    ;

blockItem
    :   statement
    |   declaration
    ;

statement
    :   compoundStatement
    |   expressionStatement
    |   jumpStatement
    ;

expressionStatement
    :   expression? ';'
    ;

jumpStatement
    :   Return expression? ';'
    ;

expression
    :   assignmentExpression (',' assignmentExpression)*
    ;

assignmentExpression
    :   logicalOrExpression
    |   unaryExpression '=' assignmentExpression
    ;

logicalOrExpression
    :   logicalAndExpression
    ;

logicalAndExpression
    :   equalityExpression
    ;

equalityExpression
    :   relationalExpression
    ;

relationalExpression
    :   additiveExpression
    ;

additiveExpression
    :   multiplicativeExpression
    |   additiveExpression '+' multiplicativeExpression
    |   additiveExpression '-' multiplicativeExpression
    ;

multiplicativeExpression
    :   unaryExpression
    ;

unaryExpression
    :   postfixExpression
    |   '-' unaryExpression
    ;

postfixExpression
    :   primaryExpression
    |   postfixExpression '(' ')'
    |   postfixExpression '(' argumentExpressionList ')'
    ;

primaryExpression
    :   Identifier
    |   Constant
    |   '(' expression ')'
    ;

parameterList
    :   parameterDeclaration (',' parameterDeclaration)*
    ;

parameterDeclaration
    :   declarationSpecifiers declarator
    ;

argumentExpressionList
    :   assignmentExpression (',' assignmentExpression)*
    ;

