}

compilationUnit
    :   translationUnit? EOF
    ;

translationUnit
    :   externalDeclaration+
    ;

externalDeclaration
    :   functionDefinition
    |   declaration
    ;

functionDefinition
    : declarationSpecifiers declarator compoundStatement
    {
        auto func = astBuilder.makeFunction($declarator.ctx, $compoundStatement.ctx);
        printAST(func);
    }
    ;

declaration
    :   declarationSpecifiers initDeclaratorList? Semi
    {
        auto decls = astBuilder.makeDeclaration($declarationSpecifiers.ctx, $initDeclaratorList.ctx);
        for (auto decl : decls) {
            printAST(decl);
        }
    }
    ;

declarationSpecifiers
    :   typeSpecifier+
    ;

typeSpecifier
    :   Int
    |   Void
    ;

declarator
    :   Identifier
    |   declarator LeftBracket RightBracket
    |   declarator LeftBracket assignmentExpression RightBracket
    |   declarator LeftParen RightParen
    |   declarator LeftParen parameterList RightParen
    ;

initDeclaratorList
    :   initDeclarator (',' initDeclarator)*
    ;

initDeclarator
    :   declarator
    |   declarator '=' initializer
    ;

initializer
    :   assignmentExpression
    |   '{' initializerList '}'
    |   '{' '}'
    ;

initializerList
    :   initializer (',' initializer)*
    ;

compoundStatement
    :   '{' blockItemList? '}'
    ;

blockItemList
    :   blockItem+
    ;

blockItem
    :   statement
    |   declaration
    ;

statement
    :   compoundStatement
    |   expressionStatement
    |   jumpStatement
    ;

expressionStatement
    :   expression? ';'
    ;

jumpStatement
    :   Return expression? ';'
    ;

expression
    :   assignmentExpression (',' assignmentExpression)*
    ;

assignmentExpression
    :   logicalOrExpression
    |   unaryExpression '=' assignmentExpression
    ;

logicalOrExpression
    :   logicalAndExpression
    ;

logicalAndExpression
    :   equalityExpression
    ;

equalityExpression
    :   relationalExpression
    ;

relationalExpression
    :   additiveExpression
    ;

additiveExpression
    :   multiplicativeExpression
    |   additiveExpression '+' multiplicativeExpression
    |   additiveExpression '-' multiplicativeExpression
    ;

multiplicativeExpression
    :   unaryExpression
    ;

unaryExpression
    :   postfixExpression
    |   '-' unaryExpression
    ;

postfixExpression
    :   primaryExpression
    |   postfixExpression '(' ')'
    |   postfixExpression '(' argumentExpressionList ')'
    ;

primaryExpression
    :   Identifier
    |   Constant
    |   '(' expression ')'
    ;

parameterList
    :   parameterDeclaration (',' parameterDeclaration)*
    ;

parameterDeclaration
    :   declarationSpecifiers declarator
    ;

argumentExpressionList
    :   assignmentExpression (',' assignmentExpression)*
    ;
